// Splinched · Leak Hunt parity tests.
//
// Run: `node assets/js/splinched-leak-hunt/leak_hunt.test.mjs`
//
// Pins the JS port to the output of the source-of-truth Python helper
// (`helpers/leak_hunt.py`). The golden numbers below were generated by
// running the real Python helper over the bundled example CSV with the same
// DEFAULT_RULES this module ships. If you change either implementation,
// re-generate the goldens and update both.

import { readFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';
import {
  parseCsv, analyze, DEFAULT_RULES,
  toFloat, normalizeDate, isPendingDate, detectFormat, sniffDelimiter,
  detectRecurring, cleanMerchantName, categorizeWithRules,
} from './leak_hunt.js';

const here = dirname(fileURLToPath(import.meta.url));
const EXAMPLE = join(here, '..', '..', 'splinched', 'leak-hunt-example.csv');

const fail = [];
function check(label, cond, detail = '') {
  if (cond) console.log(`  ✓ ${label}`);
  else fail.push(`  ✗ ${label}${detail ? ' — ' + detail : ''}`);
}
const cents = n => Math.round(n * 100) / 100;

console.log('Splinched leak-hunt parity test\n');

// ---------------------------------------------------------------------------
console.log('toFloat (money parsing):');
check('$238.60 → 238.6',  toFloat('$238.60') === 238.6);
check('($500) → -500',    toFloat('($500)') === -500);
check('+ $238.6 → 238.6', toFloat('+ $238.6') === 238.6);
check('- $500 → -500',    toFloat('- $500') === -500);
check('$2,194.24 → 2194.24', toFloat('$2,194.24') === 2194.24);
check('blank → 0',        toFloat('   ') === 0);
check('garbage → 0',      toFloat('n/a') === 0);

// ---------------------------------------------------------------------------
console.log('\nnormalizeDate:');
check('ISO passthrough',      normalizeDate('2026-03-02') === '2026-03-02');
check('US m/d/Y',             normalizeDate('03/02/2026') === '2026-03-02');
check('US m/d/y (2-digit)',   normalizeDate('3/2/26') === '2026-03-02');
check('Y/m/d',                normalizeDate('2026/03/02') === '2026-03-02');
check('d-b-Y',                normalizeDate('02-Mar-2026') === '2026-03-02');
check('strips PENDING prefix',normalizeDate('PENDING - 05/26/2026') === '2026-05-26');
check('strips Pending prefix (mixed case)', normalizeDate('Pending - 2026-05-26') === '2026-05-26');
check('invalid month rejected → raw', normalizeDate('13/40/2026') === '13/40/2026');
check('isPendingDate true',  isPendingDate('PENDING - 05/26/2026') === true);
check('isPendingDate false', isPendingDate('05/26/2026') === false);

// ---------------------------------------------------------------------------
console.log('\ndetectFormat:');
check('pnc (Withdrawals+Deposits)',
  detectFormat(['Date', 'Description', 'Withdrawals', 'Deposits', 'Balance']) === 'pnc');
check('pnc_activity',
  detectFormat(['Transaction Date', 'Transaction Description', 'Amount', 'Category', 'Balance']) === 'pnc_activity');
check('generic_v1',
  detectFormat(['Posted', 'Memo', 'Amount']) === 'generic_v1');
check('unknown',
  detectFormat(['Foo', 'Bar']) === 'unknown');

// ---------------------------------------------------------------------------
console.log('\nsniffDelimiter:');
check('comma', sniffDelimiter('a,b,c\n1,2,3') === ',');
check('tab',   sniffDelimiter('a\tb\tc\n1\t2\t3') === '\t');
check('semicolon', sniffDelimiter('a;b;c\n1;2;3') === ';');
check('pipe',  sniffDelimiter('a|b|c\n1|2|3') === '|');
check('comma despite commas inside quotes',
  sniffDelimiter('a,b,c\n"x,y",2,3\n"p,q",5,6') === ',');

// ---------------------------------------------------------------------------
console.log('\ncleanMerchantName (golden spot checks):');
check('NETFLIX.COM CARD6845 → Netflix', cleanMerchantName('NETFLIX.COM CARD6845') === 'Netflix');
check('APPLE.COM/BILL CARD6845 → Apple', cleanMerchantName('APPLE.COM/BILL CARD6845') === 'Apple');
check('STARBUCKS #1234 → Starbucks', cleanMerchantName('STARBUCKS #1234') === 'Starbucks');
check('VERIZON ... phone → Verizon Wireless',
  cleanMerchantName('VERIZON WIRELESS 800-922-0204') === 'Verizon Wireless');
check('WHOLEFDS MKT #103 → Wholefds Mkt', cleanMerchantName('WHOLEFDS MKT #103') === 'Wholefds Mkt');
check('AMAZON.COM*A12B3 CARD6845 → Amazon*A12B3',
  cleanMerchantName('AMAZON.COM*A12B3 CARD6845') === 'Amazon*A12B3');
check('STATE FARM INSURANCE → State Farm Insurance',
  cleanMerchantName('STATE FARM INSURANCE') === 'State Farm Insurance');

// ---------------------------------------------------------------------------
console.log('\ndetectRecurring (±5% of mean, outflows only):');
{
  const txs = [
    { description: 'NETFLIX', amount: 15.99 },
    { description: 'NETFLIX', amount: 15.99 },
    { description: 'STARBUCKS', amount: 6.50 },
    { description: 'STARBUCKS', amount: 6.75 },   // 1.9% off mean → recurring
    { description: 'CAR REPAIR', amount: 800 },
    { description: 'CAR REPAIR', amount: 200 },    // way off → not recurring
    { description: 'PAYCHECK', amount: -2000 },
    { description: 'PAYCHECK', amount: -2000 },    // inflows never recur
    { description: 'ONE OFF', amount: 50 },        // single → not recurring
  ];
  const flagged = detectRecurring(txs);
  check('netflix pair flagged', flagged.has(0) && flagged.has(1));
  check('starbucks pair flagged (within 5%)', flagged.has(2) && flagged.has(3));
  check('car repair NOT flagged (>5%)', !flagged.has(4) && !flagged.has(5));
  check('paychecks NOT flagged (inflow)', !flagged.has(6) && !flagged.has(7));
  check('single occurrence NOT flagged', !flagged.has(8));
  check('exactly 4 flagged', flagged.size === 4, `got ${flagged.size}`);
}

// ---------------------------------------------------------------------------
console.log('\nPNC activity sign convention (positive=outflow schema):');
{
  const csv = [
    'Transaction Date,Transaction Description,Amount,Category,Balance',
    '05/05/2026,PAYROLL,"+ $2,000.00",Income,$1.00',  // deposit → inflow (negative)
    '05/04/2026,NETFLIX,- $15.99,Sub,$1.00',          // charge  → outflow (positive)
    '05/03/2026,REFUND,($25.00),Misc,$1.00',          // parens  → outflow (positive)
    '05/02/2026,INTEREST,$2.50,Misc,$1.00',           // bare +  → inflow (negative)
  ].join('\n');
  const { records, format } = parseCsv(csv);
  check('detected pnc_activity', format === 'pnc_activity');
  check('+ deposit → -2000 (inflow)', records[0].amount === -2000);
  check('- charge → +15.99 (outflow)', records[1].amount === 15.99);
  check('(parens) → +25 (outflow)', records[2].amount === 25);
  check('bare positive → -2.5 (inflow)', records[3].amount === -2.5);
}

// ---------------------------------------------------------------------------
console.log('\ncategorizeWithRules (first match wins):');
{
  check('DOORDASH*MCDONALDS → Dining out (DoorDash beats McDonald)',
    categorizeWithRules('DOORDASH*MCDONALDS', DEFAULT_RULES).category === 'Dining out');
  check('PAYPAL *UBER → Transportation',
    categorizeWithRules('PAYPAL *UBER', DEFAULT_RULES).category === 'Transportation');
  check('TRANSFER TO SAVINGS → Internal transfer',
    categorizeWithRules('TRANSFER TO SAVINGS XXXXXX1234', DEFAULT_RULES).category === 'Internal transfer');
  check('unknown merchant → Uncategorized',
    categorizeWithRules('LOCAL HARDWARE STORE', DEFAULT_RULES).category === 'Uncategorized');
}

// ===========================================================================
console.log('\n=== INTEGRATION: example CSV vs Python goldens ===');
{
  const content = readFileSync(EXAMPLE, 'utf8');
  const { records, format } = parseCsv(content);
  check('format = pnc_activity', format === 'pnc_activity');
  check('31 records', records.length === 31, `got ${records.length}`);

  const a = analyze(records, DEFAULT_RULES);
  check('total outflow = 1385.05', cents(a.totalOutflow) === 1385.05, `got ${cents(a.totalOutflow)}`);
  check('total inflow = 6000.00', cents(a.totalInflow) === 6000, `got ${cents(a.totalInflow)}`);
  check('net = -4614.95', cents(a.net) === -4614.95, `got ${cents(a.net)}`);
  check('period 2026-03-02 → 2026-05-26',
    a.periodStart === '2026-03-02' && a.periodEnd === '2026-05-26',
    `${a.periodStart} → ${a.periodEnd}`);
  check('span = 85 days', a.spanDays === 85, `got ${a.spanDays}`);
  check('17 transactions flagged recurring', a.recurringCount === 17, `got ${a.recurringCount}`);

  // Category breakdown — pin every row.
  const GOLD_BREAKDOWN = {
    'Bills':                     { total: 554.60, count: 5, excluded: false },
    'Internal transfer':         { total: 500.00, count: 1, excluded: true  },
    'Groceries':                 { total: 284.46, count: 2, excluded: false },
    'Shopping':                  { total: 132.00, count: 2, excluded: false },
    'Transportation':            { total: 126.80, count: 3, excluded: false },
    'Streaming & subscriptions': { total: 102.92, count: 8, excluded: false },
    'Other':                     { total: 100.00, count: 1, excluded: false },
    'Dining out':                { total: 34.18,  count: 1, excluded: false },
    'Coffee':                    { total: 25.10,  count: 4, excluded: false },
    'Health':                    { total: 24.99,  count: 1, excluded: false },
    'Income':                    { total: -6000.00, count: 3, excluded: true },
  };
  check('breakdown has 11 categories', a.breakdown.length === 11, `got ${a.breakdown.length}`);
  const byCat = Object.fromEntries(a.breakdown.map(r => [r.category, r]));
  for (const [cat, g] of Object.entries(GOLD_BREAKDOWN)) {
    const row = byCat[cat];
    check(`  ${cat}: total ${g.total}, n${g.count}, excl=${g.excluded}`,
      row && cents(row.total) === g.total && row.count === g.count && row.is_excluded === g.excluded,
      row ? `got total ${cents(row.total)}, n${row.count}, excl=${row.is_excluded}` : 'missing');
  }
  // Breakdown sorted by total desc.
  check('breakdown sorted by total desc',
    a.breakdown.every((r, i) => i === 0 || a.breakdown[i - 1].total >= r.total));

  // Recurring summary — pin order + cleaned names + figures.
  const GOLD_RECURRING = [
    { name: 'State Farm Insurance', count: 2, avg: 142.30, day: 12, cat: 'Bills' },
    { name: 'Verizon Wireless',     count: 3, avg: 90.00,  day: 20, cat: 'Bills' },
    { name: 'Shell Oil 57442109',   count: 2, avg: 49.69,  day: 8,  cat: 'Transportation' },
    { name: 'Netflix',              count: 4, avg: 15.99,  day: 18, cat: 'Streaming & subscriptions' },
    { name: 'Spotify',              count: 3, avg: 11.99,  day: 15, cat: 'Streaming & subscriptions' },
    { name: 'Starbucks',            count: 3, avg: 6.62,   day: 22, cat: 'Coffee' },
  ];
  check('6 recurring groups', a.recurring.length === 6, `got ${a.recurring.length}`);
  GOLD_RECURRING.forEach((g, i) => {
    const r = a.recurring[i];
    check(`  recurring[${i}] = ${g.name} (avg ${g.avg}, n${g.count}, day ${g.day}, ${g.cat})`,
      r && r.cleaned_name === g.name && r.count === g.count &&
      cents(r.avg_amount) === g.avg && r.last_day_of_month === g.day && r.suggested_category === g.cat,
      r ? `got ${r.cleaned_name} avg ${cents(r.avg_amount)} n${r.count} day ${r.last_day_of_month} ${r.suggested_category}` : 'missing');
  });

  // Biggest transactions — pin the top 3.
  check('biggest[0] = WHOLEFDS 156.02',
    a.biggest[0].description === 'WHOLEFDS MKT #103' && cents(a.biggest[0].amount) === 156.02);
  check('biggest[1] = STATE FARM 142.30',
    a.biggest[1].description === 'STATE FARM INSURANCE' && cents(a.biggest[1].amount) === 142.30);
  check('biggest excludes transfers/income',
    a.biggest.every(t => t.category !== 'Internal transfer' && t.category !== 'Income'));

  // Pending flag survived parsing.
  const pending = records.filter(r => r.pending);
  check('1 pending row (AMAZON 05/26)',
    pending.length === 1 && pending[0].description.startsWith('AMAZON'),
    `got ${pending.length}`);
}

// ===========================================================================
if (fail.length === 0) {
  console.log('\nAll leak-hunt checks passed.');
  process.exit(0);
} else {
  console.error('\nFailures:');
  for (const f of fail) console.error(f);
  process.exit(1);
}
